const items = $input.all();

items.forEach(item => {
  const b = item.json;
  if (!b.datetime) return;

  const ms = Date.parse(b.datetime);

  if (!b.fbp) {
    b.fbp = `fb.1.${ms}.${Math.floor(Math.random() * 1e10)}`;
  }
  if (b.fbclid && !b.fbc) {
    b.fbc = `fb.1.${ms}.${b.fbclid}`;
  }
});

return items;

