// Function Item node
return items.map(item => {
  const tipo = item.json['Tipo de Atendimento'] || '';
  let categoria = 'OUTROS';

  // 1) CIRURGIA
  if (/cirurgia/i.test(tipo)) {
    categoria = 'CIRURGIA';

  // 2) SESSÃO / TERAPIA
  } else if (/sess[ãa]o|pacote|fraxx|fissuras|laser|radiofrequ[eê]ncia|led/i.test(tipo)) {
    categoria = 'SESSÃO/TERAPIA';

  // 3) PROCEDIMENTO
  } else if (/coloca[cç][ãa]o|retirada|implante|pess[áa]rio|procedimento|toxina/i.test(tipo)) {
    categoria = 'PROCEDIMENTO';

  // 4) CONSULTA
  } else if (/consulta|retorno|acolhimento|encaixe|enfermagem|visita/i.test(tipo)) {
    categoria = 'CONSULTA';
  }

  item.json['categoria_atendimento'] = categoria;
  return item;
});

